-- Add a reusable 100-word Chinese travel deck with pre-generated audio.
insert into public.template_decks (slug, name, description, level)
values (
  'du-lich-tieng-trung-100',
  'Du lịch tiếng Trung - 100 từ',
  '100 từ vựng tiếng Trung thiết yếu khi đi du lịch: sân bay, phương tiện, khách sạn, tham quan, thanh toán và tình huống khẩn cấp. Mỗi từ có pinyin, nghĩa tiếng Việt, câu ví dụ và audio tạo sẵn.',
  'Du lịch'
)
on conflict (slug) do update
set
  name = excluded.name,
  description = excluded.description,
  level = excluded.level;

with target_deck as (
  select id
  from public.template_decks
  where slug = 'du-lich-tieng-trung-100'
)
insert into public.template_cards (
  template_deck_id,
  chinese,
  pinyin,
  meaning_vi,
  example_cn,
  example_pinyin,
  example_vi,
  word_audio_url,
  sentence_audio_url,
  position
)
select
  target_deck.id,
  card.chinese,
  card.pinyin,
  card.meaning_vi,
  card.example_cn,
  card.example_pinyin,
  card.example_vi,
  card.word_audio_url,
  card.sentence_audio_url,
  card.position
from target_deck
cross join (
  values
    ('旅游', 'lǚyóu', 'du lịch', '我爱旅游，喜欢体验不同文化。', 'Wǒ ài lǚyóu，xǐhuan tǐyàn bùtóng wénhuà.', 'Tôi thích du lịch, thích trải nghiệm các nền văn hóa khác nhau.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-c8bf3f878e389b57c6ec6032.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-7b4068d1cf615c9b238f8978.mp3', 1),
    ('旅行', 'lǚxíng', 'đi du lịch, chuyến đi', '明天我们准备开始旅行，去海边。', 'Míngtiān wǒmen zhǔnbèi kāishǐ lǚxíng，qù hǎibiān.', 'Ngày mai chúng tôi chuẩn bị bắt đầu chuyến đi đến biển.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-e751bca25e1fc515534aecc2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-5530b1e55e1375a6a427d965.mp3', 2),
    ('游客', 'yóukè', 'khách du lịch', '公园里有很多来自各地的游客。', 'Gōngyuán lǐ yǒu hěn duō láizì gèdì de yóukè.', 'Trong công viên có nhiều khách du lịch đến từ nhiều nơi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-8214f290a39377031f130bb9.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-784cf3a82f1455d3ef3fa6dc.mp3', 3),
    ('导游', 'dǎoyóu', 'hướng dẫn viên du lịch', '导游详细介绍了景点的历史。', 'Dǎoyóu xiángxì jièshào le jǐngdiǎn de lìshǐ.', 'Hướng dẫn viên du lịch giới thiệu chi tiết lịch sử của điểm tham quan.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-d9c306281da3e1cfe1062467.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-2f6507fad439f83ae39033ae.mp3', 4),
    ('景点', 'jǐngdiǎn', 'điểm tham quan', '这座城市有很多著名的景点招待游客。', 'Zhè zuò chéngshì yǒu hěn duō zhùmíng de jǐngdiǎn zhāodài yóukè.', 'Thành phố này có nhiều điểm tham quan nổi tiếng để tiếp đón khách du lịch.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-bc64f4509cbb8cf86058dc6a.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-62fb77496d6a5463b995fb1f.mp3', 5),
    ('风景', 'fēngjǐng', 'phong cảnh', '山区的风景美丽，适合摄影和休闲。', 'Shānqū de fēngjǐng měilì，shìhé shèyǐng hé xiūxián.', 'Phong cảnh vùng núi rất đẹp, thích hợp chụp ảnh và nghỉ ngơi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-0f70eef46ff03c6ed8c1ebe1.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-44f43ae2d29a4d216fa3c060.mp3', 6),
    ('行程', 'xíngchéng', 'lịch trình', '我的行程包括北京、上海和西安三个城市。', 'Wǒ de xíngchéng bāokuò Běijīng, Shànghǎi hé Xī''ān sān gè chéngshì.', 'Lịch trình của tôi bao gồm ba thành phố: Bắc Kinh, Thượng Hải và Tây An.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-1fcc0ccba7f52778ce29e784.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-b6044b32754158b93e1d7356.mp3', 7),
    ('计划', 'jìhuà', 'kế hoạch', '我们的旅行计划已经制定得很详细。', 'Wǒmen de lǚxíng jìhuà yǐjīng zhìdìng de hěn xiángxì.', 'Kế hoạch du lịch của chúng tôi đã được lập rất chi tiết.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-0f6b1949b093e35266991fbe.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-c04d133cf70a6c183032640d.mp3', 8),
    ('出发', 'chūfā', 'khởi hành', '火车明天早上八点准时出发。', 'Huǒchē míngtiān zǎoshang bādiǎn zhǔnshí chūfā.', 'Tàu sẽ khởi hành đúng giờ vào 8 giờ sáng ngày mai.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-efdc22fca1c6310f550c6a58.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-1f8878c65ad411a2dcf15ce1.mp3', 9),
    ('到达', 'dàodá', 'đến nơi', '飞机准时到达了目的地机场。', 'Fēijī zhǔnshí dàodá le mùdìdì jīchǎng.', 'Máy bay đã đến nơi tại sân bay đích đến đúng giờ.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-28079a47f801a234ba54ef12.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-500def15032fc9a845f43ee5.mp3', 10),
    ('返回', 'fǎnhuí', 'trở về', '旅行结束后，大家一起乘车返回酒店。', 'Lǚxíng jiéshù hòu, dàjiā yìqǐ chéng chē fǎnhuí jiǔdiàn.', 'Sau khi kết thúc chuyến đi, mọi người cùng nhau đi xe trở về khách sạn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-572cf45ba43634b3448aadbc.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-50d8ad35ad04cbfe42694516.mp3', 11),
    ('预订', 'yùdìng', 'đặt trước', '为了保证房间，我提前预订了酒店。', 'Wèile bǎozhèng fángjiān，wǒ tíqián yùdìng le jiǔdiàn.', 'Để đảm bảo có phòng, tôi đã đặt trước khách sạn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-a0170dc9aafae25e0a3cfc45.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-afabcd4a1053f79882fc8c04.mp3', 12),
    ('取消', 'qǔxiāo', 'hủy bỏ', '因为天气恶劣，导游决定取消这次活动。', 'Yīnwèi tiānqì èliè, dǎoyóu juédìng qǔxiāo zhè cì huódòng.', 'Vì thời tiết xấu, hướng dẫn viên quyết định hủy bỏ hoạt động lần này.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-2cd0f3be8738a86cede1a145.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-7829375028389581a536c816.mp3', 13),
    ('改签', 'gǎiqiān', 'đổi vé, đổi chuyến', '航班时间改变后，我申请改签了机票。', 'Hángbān shíjiān gǎibiàn hòu, wǒ shēnqǐng gǎiqiān le jīpiào.', 'Sau khi thay đổi giờ bay, tôi đã làm thủ tục đổi vé máy bay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-928b8258b57405af7db9413d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-79b935cbf8a2df2444d9cd7f.mp3', 14),
    ('护照', 'hùzhào', 'hộ chiếu', '请确认护照有效期足够长。', 'Qǐng quèrèn hùzhào yǒuxiào qī zúgòu cháng.', 'Xin vui lòng xác nhận hộ chiếu còn thời hạn đủ dài.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-d24f1b9e50c3d3c8b3306f1e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-1b4344ee0d4ad015e2528c12.mp3', 15),
    ('签证', 'qiānzhèng', 'thị thực, visa', '前往国外，必须提前办理签证手续。', 'Qiánwǎng guówài, bìxū tíqián bànlǐ qiānzhèng shǒuxù.', 'Đi ra nước ngoài, phải làm thủ tục xin visa trước.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-a049a6815ed8881378a49058.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-f21f857f7c70c7be947ec908.mp3', 16),
    ('身份证', 'shēnfènzhèng', 'căn cước công dân', '入住酒店时，需要出示身份证验证身份。', 'Rùzhù jiǔdiàn shí, xūyào chūshì shēnfènzhèng yànzhèng shēnfèn.', 'Khi nhận phòng khách sạn, cần xuất trình chứng minh nhân dân để xác minh.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-be8fc5a81de5de07d73c0892.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-4a25c7c58672a29de44935e4.mp3', 17),
    ('机票', 'jīpiào', 'vé máy bay', '我们在网上购买了来回的机票。', 'Wǒmen zài wǎngshàng gòumǎi le láihuí de jīpiào.', 'Chúng tôi đã mua vé máy bay khứ hồi trên mạng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-15de5ae07a24afb21f7f6849.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-f8882fd80907d6a9c81cae15.mp3', 18),
    ('往返票', 'wǎngfǎnpiào', 'vé khứ hồi', '请提前购买往返票，节省费用。', 'Qǐng tíqián gòumǎi wǎngfǎnpiào, jiéshěng fèiyòng.', 'Vui lòng mua vé khứ hồi trước để tiết kiệm chi phí.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-2071619441cf2d54d5ea5f91.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-aacad5201edb31dfc83ddd28.mp3', 19),
    ('单程票', 'dānchéngpiào', 'vé một chiều', '我只买了一张单程票，下一站再购买返回票。', 'Wǒ zhǐ mǎi le yī zhāng dānchéngpiào, xià yī zhàn zài gòumǎi fǎnhuí piào.', 'Tôi chỉ mua vé một chiều, điểm tiếp theo sẽ mua vé trở về.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-eced64baeb70e34935696fe1.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-bd523a14e7b6fe5423e63348.mp3', 20),
    ('登机牌', 'dēngjīpái', 'thẻ lên máy bay', '请出示您的登机牌和护照。', 'Qǐng chūshì nín de dēngjīpái hé hùzhào.', 'Vui lòng xuất trình thẻ lên máy bay và hộ chiếu của bạn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-0f9e6796f8b21270632e418d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-6edb0faa15f7421dbf8de3f1.mp3', 21),
    ('行李', 'xíngli', 'hành lý', '我的行李里有重要的文件。', 'Wǒ de xíngli lǐ yǒu zhòngyào de wénjiàn.', 'Hành lý của tôi có những tài liệu quan trọng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-48169ad8cbbb838d026779d5.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-9ad13c782a03ea1a2ef89150.mp3', 22),
    ('行李箱', 'xínglixiāng', 'va li', '请把行李箱放到行李架上。', 'Qǐng bǎ xínglixiāng fàng dào xíngli jià shàng.', 'Xin hãy đặt va li lên giá hành lý.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-4bda402bd5b4c4e3f034aa79.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-beedec25000c678721fc1a86.mp3', 23),
    ('托运', 'tuōyùn', 'ký gửi hành lý', '我需要托运这个大箱子。', 'Wǒ xūyào tuōyùn zhège dà xiāngzi.', 'Tôi cần ký gửi cái va li lớn này.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-e10e2fc43c28e04a4d0a1735.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-626d96c7712af59f8d10bab0.mp3', 24),
    ('手提行李', 'shǒutí xíngli', 'hành lý xách tay', '手提行李不能超过七公斤。', 'Shǒutí xíngli bùnéng chāoguò qī gōngjīn.', 'Hành lý xách tay không được vượt quá bảy cân.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-23f0a03d956fd7182bcca7d8.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-1b1b281a59197d0703a2037b.mp3', 25),
    ('安检', 'ānjiǎn', 'kiểm tra an ninh', '排队通过安检，请准备好登机牌。', 'Páiduì tōngguò ānjiǎn, qǐng zhǔnbèi hǎo dēngjīpái.', 'Xếp hàng qua kiểm tra an ninh, vui lòng chuẩn bị thẻ lên máy bay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-121293d774c17bea4b2a9ec0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-190d9074a649a983107658b9.mp3', 26),
