    ('支付', 'zhīfù', 'thanh toán', '您可以用手机支付车票费用。', 'Nín kěyǐ yòng shǒujī zhīfù chēpiào fèiyòng.', 'Bạn có thể dùng điện thoại thanh toán chi phí vé xe.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-5d3ba34cc66cea451b2876a2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-a20be4798005cc7e5948adb3.mp3', 90),
    ('费用', 'fèiyòng', 'chi phí', '这次旅游的费用包括交通和住宿。', 'Zhè cì lǚyóu de fèiyòng bāokuò jiāotōng hé zhùsù.', 'Chi phí chuyến du lịch này bao gồm giao thông và chỗ ở.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-7fe8603c084eb991ef6410f8.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-057fcf9a4793debc06987318.mp3', 91),
    ('预算', 'yùsuàn', 'ngân sách', '请帮我制定一下旅行的预算计划。', 'Qǐng bāng wǒ zhìdìng yīxià lǚxíng de yùsuàn jìhuà.', 'Làm ơn giúp tôi lên kế hoạch ngân sách du lịch.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-bd8dbd5724735390a29cb996.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-9814974d47752a85dc9affb9.mp3', 92),
    ('保险', 'bǎoxiǎn', 'bảo hiểm', '出发前请确认购买了旅游保险。', 'Chūfā qián qǐng quèrèn gòumǎile lǚyóu bǎoxiǎn.', 'Trước khi khởi hành hãy xác nhận đã mua bảo hiểm du lịch.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-f0ca6e47a6af96bb1cd92a49.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-782075cd170da0df76f42908.mp3', 93),
    ('旅游保险', 'lǚyóu bǎoxiǎn', 'bảo hiểm du lịch', '旅游保险可以保障你遇到紧急情况。', 'Lǚyóu bǎoxiǎn kěyǐ bǎozhàng nǐ yù dào jǐnjí qíngkuàng.', 'Bảo hiểm du lịch có thể bảo vệ bạn khi gặp tình huống khẩn cấp.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-eb3b99f17d15a98e5bb8c41b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-70a5614082ecdce261776b91.mp3', 94),
    ('紧急情况', 'jǐnjí qíngkuàng', 'tình huống khẩn cấp', '遇到紧急情况请立即联系当地警察。', 'Yù dào jǐnjí qíngkuàng qǐng lìjí liánxì dāngdì jǐngchá.', 'Gặp tình huống khẩn cấp xin hãy liên hệ ngay cảnh sát địa phương.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-6cb91f126a4660a9d790250c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-e685b6d3d322cb1ee1add2b2.mp3', 95),
    ('医院', 'yīyuàn', 'bệnh viện', '生病时请及时去附近的医院治疗。', 'Shēngbìng shí qǐng jíshí qù fùjìn de yīyuàn zhìliáo.', 'Khi bị bệnh hãy kịp thời đến bệnh viện gần nhất điều trị.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-1f6835c0d878fa0e14800964.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-34932be98da812b838d5f62f.mp3', 96),
    ('警察', 'jǐngchá', 'cảnh sát', '请向警察说明你的身份和问题。', 'Qǐng xiàng jǐngchá shuōmíng nǐ de shēnfèn hé wèntí.', 'Vui lòng trình bày với cảnh sát về thân phận và vấn đề của bạn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-910a3de487b5956f3ae52860.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-17918f66f39e2815417a7bb1.mp3', 97),
    ('求助', 'qiúzhù', 'cầu cứu, nhờ giúp đỡ', '如果迷路了，可以向当地人求助。', 'Rúguǒ mílù le, kěyǐ xiàng dāngdìrén qiúzhù.', 'Nếu bị lạc, bạn có thể nhờ người địa phương giúp đỡ.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-dbc7cac5de5feb6290015472.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-e07abbcddbb3bce07114d20a.mp3', 98),
    ('天气预报', 'tiānqì yùbào', 'dự báo thời tiết', '天气预报说明天有雨，带伞出门。', 'Tiānqì yùbào shuō míngtiān yǒu yǔ, dài sǎn chūmén.', 'Dự báo thời tiết nói ngày mai sẽ mưa, hãy mang ô khi ra ngoài.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-e2d89f9d3097ecc17f5e56cf.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-fdfcfae99461241b44bdc699.mp3', 99),
    ('当地人', 'dāngdìrén', 'người địa phương', '和当地人聊天能了解更多文化。', 'Hé dāngdìrén liáotiān néng liǎojiě gèng duō wénhuà.', 'Nói chuyện với người địa phương có thể hiểu thêm nhiều về văn hóa.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/word-7b24126381328462170881e1.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/du-lich-tieng-trung-100/sentence-ba95f6356a633091d03460a4.mp3', 100)
) as card(
  chinese,
  pinyin,
  meaning_vi,
  example_cn,
  example_pinyin,
  example_vi,
  word_audio_url,
  sentence_audio_url,
  position
)
on conflict (template_deck_id, chinese) do update
set
  pinyin = excluded.pinyin,
  meaning_vi = excluded.meaning_vi,
  example_cn = excluded.example_cn,
  example_pinyin = excluded.example_pinyin,
  example_vi = excluded.example_vi,
  word_audio_url = excluded.word_audio_url,
  sentence_audio_url = excluded.sentence_audio_url,
  position = excluded.position;
